 1	import { Given, Then } from '@badeball/cypress-cucumber-preprocessor';
 2	
 3	const auth_strategy = Cypress.env('auth_strategy');
 4	
 5	Given('user clicks on admin', () => {
 6	  if (auth_strategy === 'openshift') {
 7	    cy.get('#user-dropdown-toggle').click();
 8	  }
 9	});
10	
11	Given('user logout successfully', () => {
12	  if (auth_strategy === 'openshift') {
13	    cy.intercept('**/api/logout').as('logout');
14	    cy.get('.pf-v5-c-dropdown__menu-item').click();
15	  }
16	});
17	
18	Then('user verify the logout', () => {
19	  if (auth_strategy === 'openshift') {
20	    cy.wait('@logout').its('response.statusCode').should('eq', 204);
21	  }
22	});

